import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{r as o,o as l,c as i,b as n,d as a,e as p,a as s}from"./app-e1a47c85.js";const k="/assets/images/vasvari/prototype-comic-1-en.webp",r="/assets/images/vasvari/prototype-comic-2-en.webp",c="/assets/images/vasvari/prototype-comic-3-en.webp",u="/assets/images/vasvari/singleton.webp",d="/assets/images/vasvari/singleton-comic-1-en.webp",m="/assets/images/vasvari/builder-en.webp",z="/assets/images/vasvari/problem1.webp",g="/assets/images/vasvari/problem2.webp",v="/assets/images/vasvari/solution1.webp",y="/assets/images/vasvari/builder-comic-1-en.webp",b="/assets/images/vasvari/builder-comic-2-en.webp",h={},f=s('<h1 id="tervezesi-mintak" tabindex="-1"><a class="header-anchor" href="#tervezesi-mintak" aria-hidden="true">#</a> Tervezési minták</h1><p>A tervezési minták a szoftvertervezésben gyakran előforduló problémák tipikus megoldásai. Olyanok, mint előre elkészített tervrajzok, amelyeket testre szabhatsz, hogy megoldj egy visszatérő tervezési problémát a kódodban.</p><p>Nem találhatsz csak úgy egy mintát, és másolhatod be a programodba, ahogyan azt a készen kapható függvények vagy könyvtárak esetében megteheted. A minta nem egy konkrét kódrészlet, hanem egy általános koncepció egy adott probléma megoldására. Követheti a minta részleteit, és olyan megoldást implementálhat, amely megfelel a program realitásának.</p><p>A mintákat gyakran összekeverik az algoritmusokkal, mivel mindkét fogalom bizonyos ismert problémák tipikus megoldásait írja le. Míg egy algoritmus mindig olyan műveletek egyértelmű halmazát határozza meg, amelyekkel valamilyen célt lehet elérni, addig egy minta egy megoldás magas szintű leírása. Ugyanannak a mintának a kódja két különböző programra alkalmazva eltérő lehet.</p><p>Az algoritmus analógiája akár egy recept: mindkettőnek egyértelmű lépései vannak a cél eléréséhez. Ezzel szemben egy minta inkább olyan, mint egy tervrajz: látható, hogy mi az eredmény és annak jellemzői, de a végrehajtás pontos sorrendje már csak rajtunk múlik.</p><h2 id="mibol-all-a-minta" tabindex="-1"><a class="header-anchor" href="#mibol-all-a-minta" aria-hidden="true">#</a> Miből áll a minta?</h2><p>A legtöbb mintát nagyon formálisan írják le, hogy az emberek sokféle kontextusban reprodukálni tudják őket. Itt vannak azok a szempontok, amelyek általában szerepelnek egy minta leírásában:</p><ul><li>A minta szándéka röviden leírja a problémát és a megoldást.</li><li>A motiváció tovább magyarázza a problémát és a megoldást, amelyet a minta lehetővé tesz.</li><li>Az osztályok szerkezete bemutatja a minta egyes részeit és azok kapcsolatát.</li><li>Kódpélda valamelyik népszerű programozási nyelven, amely megkönnyíti a minta mögötti gondolat megértését.</li></ul><p>Egyes mintakatalógusok egyéb hasznos részleteket is felsorolnak, például a minta alkalmazhatóságát, a megvalósítás lépéseit és a más mintákkal való kapcsolatokat.</p><h2 id="a-mintak-tortenete" tabindex="-1"><a class="header-anchor" href="#a-mintak-tortenete" aria-hidden="true">#</a> A minták története</h2><p>Ki találta fel a mintákat? Ez egy jó, de nem túl pontos kérdés. A tervezési minták nem homályos, kifinomult fogalmak - épp ellenkezőleg. A minták tipikus megoldások az objektumorientált tervezés gyakori problémáira. Amikor egy megoldás újra és újra megismétlődik különböző projektekben, valaki végül nevet ad neki, és részletesen leírja a megoldást. Alapvetően így fedeznek fel egy mintát.</p><p>A minták fogalmát először <strong>Christopher Alexander</strong> írta le A <em>Pattern Language</em> című könyvében: Towns, Buildings, Construction. A könyv a városi környezet tervezésének &quot;nyelvét&quot; írja le. Ennek a nyelvnek az egységei a minták. Ezek leírhatják, hogy milyen magasak legyenek az ablakok, hány szintje legyen egy épületnek, mekkora zöldterületeknek kell lenniük egy környéken, és így tovább.</p><p>Az ötletet négy szerző vette fel: <strong>Erich Gamma</strong>, <strong>John Vlissides</strong>, <strong>Ralph Johnson</strong> és <strong>Richard Helm</strong>. 1994-ben kiadták a <strong>Design Patterns: Elements of Reusable Object-Oriented Software</strong> (<em>Programtervezési ​minták: Újrahasznosítható elemek objektumközpontú programokhoz</em>) című könyvükben, amelyben a tervezési minták koncepcióját a programozásra alkalmazták. A könyv 23 mintát tartalmazott, amelyek az objektumorientált tervezés különböző problémáit oldották meg, és nagyon gyorsan bestsellerré vált. Hosszú neve miatt az emberek &quot;a négyes banda könyvének&quot; kezdték nevezni, amit hamarosan egyszerűen <em>&quot;a GoF<sup class="footnote-ref"><a href="#footnote1">[1]</a><a class="footnote-anchor" id="footnote-ref1"></a></sup>-könyvre&quot;</em> rövidítettek.</p><p>Azóta több tucat más objektumorientált mintát is felfedeztek. A <em>&quot;minta-megközelítés&quot;</em> más programozási területeken is nagyon népszerűvé vált, így ma már rengeteg más minta is létezik.</p><h2 id="miert-tanuljak-mintakat" tabindex="-1"><a class="header-anchor" href="#miert-tanuljak-mintakat" aria-hidden="true">#</a> Miért tanuljak mintákat?</h2><p>Az igazság az, hogy akár évekig is dolgozhatsz programozóként anélkül, hogy egyetlen mintát is ismernél. Sokan éppen ezt teszik. De még ebben az esetben is előfordulhat, hogy úgy valósítasz meg néhány mintát, hogy nem is tudsz róla. Akkor miért töltenél időt a megtanulásukkal?</p><ul><li><p>A tervezési minták olyan eszköztárat jelentenek, amely a szoftvertervezés során felmerülő gyakori problémákra kínál kipróbált és tesztelt megoldásokat. Még ha soha nem is találkozik ezekkel a problémákkal, a minták ismerete akkor is hasznos, mert megtanítja, hogyan oldhat meg mindenféle problémát az objektumorientált tervezés elveinek felhasználásával.</p></li><li><p>A tervezési minták olyan közös nyelvet határoznak meg, amelyet Ön és csapattársai a hatékonyabb kommunikáció érdekében használhatnak. Mondhatod, hogy <em>&quot;Ó, erre használj egy Singletont&quot;</em>, és mindenki meg fogja érteni a javaslatod mögött rejlő ötletet. Nem kell elmagyarázni, mi az a <code>singleton</code>, ha ismeri a mintát és a nevét.</p></li></ul><h2 id="a-mintak-kritikaja" tabindex="-1"><a class="header-anchor" href="#a-mintak-kritikaja" aria-hidden="true">#</a> A minták kritikája</h2><p>Úgy tűnik, csak a lusta emberek nem kritizálták még a tervezési mintákat. Nézzük meg a legjellemzőbb érveket a minták használata ellen.</p><h3 id="a-tervezesi-mintak-hianyzo-nyelvi-jellemzok" tabindex="-1"><a class="header-anchor" href="#a-tervezesi-mintak-hianyzo-nyelvi-jellemzok" aria-hidden="true">#</a> A tervezési minták hiányzó nyelvi jellemzők</h3><p>Általában akkor merül fel a minták iránti igény, amikor az emberek olyan programozási nyelvet vagy technológiát választanak, amelyből hiányzik a szükséges absztrakciós szint.</p><p>Például a <em>Stratégia</em> minta a legtöbb modern programozási nyelvben egy egyszerű névtelen (<em>lambda</em>) függvénnyel megvalósítható.</p><h3 id="hatastalan-megoldasok" tabindex="-1"><a class="header-anchor" href="#hatastalan-megoldasok" aria-hidden="true">#</a> Hatástalan megoldások</h3><p>A minták olyan megközelítéseket próbálnak rendszerezni, amelyeket már széles körben használnak. Ezt az egységesítést sokan dogmának tekintik, és <em>&quot;betű szerint&quot;</em> implementálják a mintákat, anélkül, hogy a projektjük kontextusához igazítanák őket.</p><h3 id="indokolatlan-hasznalat" tabindex="-1"><a class="header-anchor" href="#indokolatlan-hasznalat" aria-hidden="true">#</a> Indokolatlan használat</h3><div class="hint-container warning"><p class="hint-container-title">Ha csak egy kalapácsod van, minden szögnek tűnik.</p></div><p>Ez a probléma sok kezdőt kísértenek, akik csak most ismerkednek a mintákkal. Miután megismerték a mintákat, megpróbálják mindenhol alkalmazni őket, még olyan helyzetekben is, ahol egyszerűbb kód is megfelelne.</p><h2 id="a-mintak-osztalyozasa" tabindex="-1"><a class="header-anchor" href="#a-mintak-osztalyozasa" aria-hidden="true">#</a> A minták osztályozása</h2><p>A tervezési minták összetettségük, részletességük és a tervezett rendszer egészére való alkalmazhatóságuk mértéke alapján különböznek egymástól. Szeretem az útépítés analógiáját: egy kereszteződést biztonságosabbá lehet tenni néhány közlekedési lámpa telepítésével, vagy egy teljes többszintes csomópont építésével, földalatti átjárókkal a gyalogosok számára.</p><p>A legalapvetőbb és legalacsonyabb szintű mintákat gyakran idiómáknak<sup class="footnote-ref"><a href="#footnote2">[2]</a><a class="footnote-anchor" id="footnote-ref2"></a></sup> nevezik. Ezek általában csak egyetlen programozási nyelvre vonatkoznak.</p><p>A legáltalánosabb és legmagasabb szintű minták az architektúrális minták. A fejlesztők gyakorlatilag bármilyen nyelven megvalósíthatják ezeket a mintákat. Más mintákkal ellentétben ezek a minták egy egész alkalmazás architektúrájának megtervezésére használhatók.</p><p>Ezenkívül minden minta kategorizálható a szándékuk vagy céljuk szerint. Ez a könyv a minták három fő csoportját tárgyalja:</p><p>Az <strong>alkotási minták</strong> olyan objektumalkotási mechanizmusokat biztosítanak, amelyek növelik a rugalmasságot és a meglévő kód újrafelhasználását.</p><p>A <strong>strukturális minták</strong> elmagyarázzák, hogyan lehet objektumokat és osztályokat nagyobb struktúrákba összerakni, miközben ezek a struktúrák rugalmasak és hatékonyak maradnak.</p><p>A <strong>viselkedési minták</strong> gondoskodnak a hatékony kommunikációról és az objektumok közötti felelősségek kiosztásáról.</p><h3 id="alkotoi-tervezesi-mintak" tabindex="-1"><a class="header-anchor" href="#alkotoi-tervezesi-mintak" aria-hidden="true">#</a> Alkotói tervezési minták</h3><p>A kreatív tervezési minták különböző objektum létrehozási mechanizmusokat biztosítanak, amelyek növelik a rugalmasságot és a meglévő kód újrafelhasználását.</p><h2 id="prototype-prototipus" tabindex="-1"><a class="header-anchor" href="#prototype-prototipus" aria-hidden="true">#</a> Prototype (Prototípus)</h2><p><em>Más néven: Clone</em></p><h3 id="celkituzes" tabindex="-1"><a class="header-anchor" href="#celkituzes" aria-hidden="true">#</a> Célkitűzés</h3><p>A prototype egy olyan tervezési minta, amely lehetővé teszi a meglévő objektumok másolását anélkül, hogy a kódod függne annak osztályaitól.</p><h3 id="problema" tabindex="-1"><a class="header-anchor" href="#problema" aria-hidden="true">#</a> Probléma</h3><p>Tegyük fel, hogy van egy objektumunk, és pontos másolatot szeretnénk készíteni róla. Hogyan csinálnád? Először is létre kell hoznod egy új objektumot ugyanabból az osztályból. Ezután végig kell menned az eredeti objektum összes mezőjén, és át kell másolnod az értékeiket az új objektumba.</p><p>Szép! De van egy bökkenő. Nem minden objektum másolható így, mert az objektum néhány mezője privát lehet, és az objektumon kívülről nem látható.</p><figure><img src="'+k+`" alt="Egy objektum &quot;kívülről&quot; történő másolása nem mindig lehetséges." tabindex="0" loading="lazy"><figcaption>Egy objektum &quot;kívülről&quot; történő másolása nem mindig lehetséges.</figcaption></figure><p>Van még egy probléma a közvetlen megközelítéssel. Mivel a duplikátum létrehozásához ismerned kell az objektum osztályát, a kódod függővé válik az osztálytól. Ha az extra függőség nem ijeszt meg, van egy másik csapda is. Néha csak azt az interfészt ismerjük, amelyet az objektum követ, de a konkrét osztályát nem, amikor például egy metódus paramétere minden olyan objektumot elfogad, amely valamilyen interfészt követ.</p><div class="hint-container info"><p class="hint-container-title">Interface</p><p>A Java nyelvben az interfész (<code>interface</code>) egy absztrakt osztályokat definiáló szerkezet, amely csak metódus szignatúrákat tartalmaz, de nincs bennük konkrét implementáció. Az interfészek lehetővé teszik, hogy egy vagy több osztály implementálja őket, és így megvalósítsa az interfészben meghatározott metódusokat. Az interfészek segítenek a kód újrafelhasználhatóságban, a többszörös öröklődés problémáinak elkerülésében és a rugalmasabb programozásban.</p><p>Az interfész definiálása a következőképpen történik a Java-ban:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">interface</span> <span class="token class-name">MyInterface</span> <span class="token punctuation">{</span>
    <span class="token comment">// Metódus szignatúrák (nincs implementáció)</span>
    <span class="token keyword">void</span> <span class="token function">method1</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token keyword">int</span> <span class="token function">method2</span><span class="token punctuation">(</span><span class="token keyword">int</span> num1<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Az interfész definíciója az <code>interface</code> kulcsszóval kezdődik, majd a benne deklarált metódusok követik. Az interfészen belül csak metódusokat és konstansokat (alapértelmezett vagy <code>static final</code> változókat) lehet deklarálni. Az interfészek nem tartalmaznak attribútumokat (adattagokat).</p><p>Az interfészt implementáló osztályok a <code>implements</code> kulcsszóval implementálhatják az interfészt:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">class</span> <span class="token class-name">MyClass</span> <span class="token keyword">implements</span> <span class="token class-name">MyInterface</span> <span class="token punctuation">{</span>

    <span class="token annotation punctuation">@Override</span>
    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">method1</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token comment">// Implementáció</span>
    <span class="token punctuation">}</span>

    <span class="token annotation punctuation">@Override</span>
    <span class="token keyword">public</span> <span class="token keyword">int</span> <span class="token function">method2</span><span class="token punctuation">(</span><span class="token keyword">int</span> num1<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token comment">// Implementáció</span>
        <span class="token keyword">return</span> <span class="token number">0</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Egy osztály több interfészt is implementálhat, és minden interfészben meghatározott metódust meg kell valósítania. Az interfészek segítenek a Java-ban a többes öröklődés szimulálásában, mivel egy osztály csak egy szülőtől örökölhet, de több interfészt is implementálhat.</p><p>Az interfészek hasznosak az olyan helyzetekben, amikor több osztály között közös viselkedést szeretnénk definiálni. Az interfészek elősegítik a kód újrafelhasználhatóságát és a programok kiterjeszthetőségét.</p></div><h3 id="megoldas" tabindex="-1"><a class="header-anchor" href="#megoldas" aria-hidden="true">#</a> Megoldás</h3><p>A prototípus minta a klónozási folyamatot a klónozandó objektumokhoz delegálja. A minta egy közös interfészt deklarál minden olyan objektum számára, amely támogatja a klónozást. Ez az interfész lehetővé teszi egy objektum klónozását anélkül, hogy a kódot az adott objektum osztályához kötnénk. Általában egy ilyen interfész csak egyetlen klónozási metódust tartalmaz.</p><p>A klónozó metódus végrehajtása minden osztályban nagyon hasonló. A metódus létrehoz egy objektumot az aktuális osztályból, és a régi objektum összes mezőértékét átviszi az újba. Még a privát mezőket is át lehet másolni, mivel a legtöbb programozási nyelv lehetővé teszi, hogy az objektumok hozzáférjenek más, ugyanahhoz az osztályhoz tartozó objektumok privát mezőihez.</p><p>A klónozást támogató objektumot prototípusnak nevezzük. Ha az objektumok több tucat mezővel és több száz lehetséges konfigurációval rendelkeznek, a klónozás az alosztályozás alternatívájaként szolgálhat.</p><figure><img src="`+r+'" alt="Az előre elkészített prototípusok az alosztályozás alternatívája lehet." tabindex="0" loading="lazy"><figcaption>Az előre elkészített prototípusok az alosztályozás alternatívája lehet.</figcaption></figure><p>A következőképpen működik: létrehozol egy sor objektumot, amelyeket különböző módon konfigurálhatsz. Amikor szükséged van egy olyan objektumra, mint amilyet konfiguráltál, egyszerűen klónozol egy prototípust ahelyett, hogy a semmiből építenél egy új objektumot.</p><h3 id="valo-vilagbeli-analogia" tabindex="-1"><a class="header-anchor" href="#valo-vilagbeli-analogia" aria-hidden="true">#</a> Való világbeli analógia</h3><p>A való életben a prototípusokat különböző tesztek elvégzésére használják, mielőtt egy termék sorozatgyártását megkezdenék. Ebben az esetben azonban a prototípusok nem vesznek részt a tényleges gyártásban, ehelyett passzív szerepet játszanak.</p><figure><img src="'+c+`" alt="Egy sejt osztódása." tabindex="0" loading="lazy"><figcaption>Egy sejt osztódása.</figcaption></figure><p>Mivel az ipari prototípusok nem igazán másolják önmagukat, a mintához sokkal közelebbi analógia a mitotikus<sup class="footnote-ref"><a href="#footnote3">[3]</a><a class="footnote-anchor" id="footnote-ref3"></a></sup> sejtosztódás folyamata (biológia, emlékszik?). A mitotikus osztódás után egy pár azonos sejt jön létre. Az eredeti sejt prototípusként működik, és aktív szerepet vállal a másolat létrehozásában.</p><h3 id="hogyan-kell-megvalositani" tabindex="-1"><a class="header-anchor" href="#hogyan-kell-megvalositani" aria-hidden="true">#</a> Hogyan kell megvalósítani?</h3><div class="hint-container info"><p class="hint-container-title">Ennek a mintának a célja az objektumok klónozása, amikor egy objektumot többször is használni szeretnénk, de nem akarjuk újra és újra létrehozni.</p></div><p>Ebben a példában létrehozunk egy egyszerű osztályt, amit klónozni szeretnénk, és implementáljuk a <code>Cloneable</code> interfészt, valamint felülírjuk a <code>clone</code> metódust:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">PrototypeExample</span> <span class="token keyword">implements</span> <span class="token class-name">Cloneable</span> <span class="token punctuation">{</span>
    <span class="token keyword">private</span> <span class="token class-name">String</span> data<span class="token punctuation">;</span>

    <span class="token keyword">public</span> <span class="token class-name">PrototypeExample</span><span class="token punctuation">(</span><span class="token class-name">String</span> data<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>data <span class="token operator">=</span> data<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token class-name">String</span> <span class="token function">getData</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">return</span> data<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">setData</span><span class="token punctuation">(</span><span class="token class-name">String</span> data<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>data <span class="token operator">=</span> data<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token annotation punctuation">@Override</span>
    <span class="token keyword">public</span> <span class="token class-name">PrototypeExample</span> <span class="token function">clone</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">try</span> <span class="token punctuation">{</span>
            <span class="token keyword">return</span> <span class="token punctuation">(</span><span class="token class-name">PrototypeExample</span><span class="token punctuation">)</span> <span class="token keyword">super</span><span class="token punctuation">.</span><span class="token function">clone</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">CloneNotSupportedException</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span>
            <span class="token keyword">return</span> <span class="token keyword">null</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token class-name">PrototypeExample</span> original <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">PrototypeExample</span><span class="token punctuation">(</span><span class="token string">&quot;Eredeti adat&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token class-name">PrototypeExample</span> clone <span class="token operator">=</span> original<span class="token punctuation">.</span><span class="token function">clone</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Eredeti objektum adat: &quot;</span> <span class="token operator">+</span> original<span class="token punctuation">.</span><span class="token function">getData</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;Klónozott objektum adat: &quot;</span> <span class="token operator">+</span> clone<span class="token punctuation">.</span><span class="token function">getData</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ebben a példában létrehoztuk az <code>PrototypeExample</code> osztályt, amely tartalmaz egy <code>data</code> nevű adattagot. Az osztály implementálja a <code>Cloneable</code> interfészt, majd felülírjuk a <code>clone</code> metódust, amely segítségével klónozni tudjuk az objektumot.</p><p>A <code>main</code> metódusban létrehozunk egy eredeti objektumot, majd klónozunk egy másolatot belőle. Mindkét objektumnak ugyanaz az adattagja, és miután lefuttatjuk a programot, meggyőződhetünk róla, hogy a klónozott objektum az eredeti objektum másolata.</p><h3 id="elonyok-es-hatranyok" tabindex="-1"><a class="header-anchor" href="#elonyok-es-hatranyok" aria-hidden="true">#</a> Előnyök és hátrányok</h3><p><i class="fa-solid fa-plus" style="color:green;"></i> Lehetőség van objektumok klónozására anélkül, hogy szorosan kapcsolódnának a konkrét osztályokhoz.</p><p><i class="fa-solid fa-plus" style="color:green;"></i> Megszabadulhatunk a ismétlődő objektum inicializációs kódoktól.</p><p><i class="fa-solid fa-plus" style="color:green;"></i> Kényelmesebben állíthat elő összetett objektumokat.</p><p><i class="fa-solid fa-plus" style="color:green;"></i> Alternatívát kap az öröklés helyett.</p><p><i class="fa-solid fa-minus" style="color:red;"></i> Összetett objektumok klónozása nehézségeket okozhat, ha azok kölcsönösen egymásra hivatkoznak.</p><h2 id="singleton" tabindex="-1"><a class="header-anchor" href="#singleton" aria-hidden="true">#</a> Singleton</h2><figure><img src="`+u+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="celkituzes-1" tabindex="-1"><a class="header-anchor" href="#celkituzes-1" aria-hidden="true">#</a> Célkitűzés</h3><p>A <code>singleton</code> egy olyan tervezési minta, amely lehetővé teszi, hogy egy osztálynak csak egy példánya legyen, miközben globális hozzáférést biztosít ehhez a példányhoz.</p><h3 id="problema-1" tabindex="-1"><a class="header-anchor" href="#problema-1" aria-hidden="true">#</a> Probléma</h3>',74),j=n("code",null,"Singleton",-1),A={href:"https://hu.wikipedia.org/wiki/Egyetlen_felel%C5%91ss%C3%A9g_elve",target:"_blank",rel:"noopener noreferrer"},w=s('<ol><li><strong>Biztosítja, hogy egy osztálynak csak egyetlen példánya legyen.</strong> Miért akarja bárki is ellenőrizni, hogy hány példánya van egy osztálynak? A leggyakoribb ok erre az, hogy ellenőrizni akarjuk a hozzáférést valamilyen megosztott erőforráshoz - például egy adatbázishoz vagy egy fájlhoz.</li></ol><p><em>Ez így működik:</em> képzeljük el, hogy létrehoztunk egy objektumot, de egy idő után úgy döntöttünk, hogy létrehozunk egy újat. Ahelyett, hogy egy új objektumot kapna, azt kapja, amit már létrehozott.</p><p>Vegye figyelembe, hogy ezt a viselkedést lehetetlen egy hagyományos konstruktorral megvalósítani, mivel egy konstruktorhívásnak eleve mindig egy új objektumot kell visszaadnia.</p><figure><img src="'+d+`" alt="Az ügyfelek talán észre sem veszik, hogy állandóan ugyanazzal az objektummal dolgoznak." tabindex="0" loading="lazy"><figcaption>Az ügyfelek talán észre sem veszik, hogy állandóan ugyanazzal az objektummal dolgoznak.</figcaption></figure><ol start="2"><li><strong>Biztosít egy globális hozzáférési pontot az adott példányhoz.</strong> Emlékszel azokra a globális változókra, amelyeket néhány alapvető objektum tárolására használtál? Bár nagyon praktikusak, de nagyon nem biztonságosak is, mivel bármely kód felülírhatja a változók tartalmát, és összeomolhat az alkalmazás.</li></ol><p>A globális változókhoz hasonlóan a <code>Singleton</code> minta is lehetővé teszi, hogy a program bármely pontjáról elérjen egy objektumot. Ugyanakkor megvédi ezt a példányt attól, hogy más kód felülírja.</p><p>Ennek a problémának van egy másik oldala is: nem akarjuk, hogy az #1. problémát megoldó kód szétszóródjon a programban. Sokkal jobb, ha egy osztályon belül van, különösen, ha a kód többi része már függ tőle.</p><div class="hint-container info"><p class="hint-container-title">Manapság a Singleton minta annyira népszerűvé vált, hogy az emberek akkor is singletonnak neveznek valamit, ha az csak a felsorolt problémák egyikét oldja meg.</p></div><h3 id="megoldas-1" tabindex="-1"><a class="header-anchor" href="#megoldas-1" aria-hidden="true">#</a> Megoldás</h3><p>A <code>Singleton</code> minden implementációjában közös ez a két lépés:</p><ul><li><p>Az alapértelmezett konstruktort priváttá kell tenni, hogy más objektumok ne használhassák a new operátort a <code>Singleton</code> osztállyal.<br> Hozzon létre egy statikus metódust, amely konstruktorként működik. A motorháztető alatt ez a metódus meghívja a privát konstruktort, hogy létrehozzon egy objektumot, és egy statikus mezőbe menti azt. A metódus minden következő hívása visszaadja a tárolt objektumot.</p></li><li><p>Ha a kódja hozzáfér a <code>Singleton</code> osztályhoz, akkor képes meghívni a <code>Singleton</code> statikus metódusát. Így amikor ezt a metódust meghívja, mindig ugyanazt az objektumot kapja vissza.</p></li></ul><h3 id="valo-vilagbeli-analogia-1" tabindex="-1"><a class="header-anchor" href="#valo-vilagbeli-analogia-1" aria-hidden="true">#</a> Való világbeli analógia</h3><p>A kormány kiváló példája a <code>Singleton</code> mintának. Egy országnak csak egy hivatalos kormánya lehet. Függetlenül a kormányt alkotó személyek személyazonosságától, a <em>&quot;X kormány&quot;</em> cím egy globális hozzáférési pont, amely azonosítja a felelős személyek csoportját.</p><h3 id="hogyan-kell-megvalositani-1" tabindex="-1"><a class="header-anchor" href="#hogyan-kell-megvalositani-1" aria-hidden="true">#</a> Hogyan kell megvalósítani?</h3><ol><li><p>Adjunk hozzá egy privát statikus mezőt az osztályhoz a <code>singleton</code> példány tárolására.</p></li><li><p>Deklaráljunk egy nyilvános statikus metódust a <code>singleton</code> példány kinyeréséhez.</p></li><li><p>Implementáljuk a &quot;lusta inicializálást&quot;<sup class="footnote-ref"><a href="#footnote4">[4]</a><a class="footnote-anchor" id="footnote-ref4"></a></sup> a statikus metóduson belül. Az első híváskor egy új objektumot kell létrehoznia, és azt a statikus mezőbe helyeznie. A metódusnak minden további híváskor mindig ezt a példányt kell visszaadnia.</p></li><li><p>Az osztály konstruktora legyen privát. Az osztály statikus metódusa továbbra is képes lesz meghívni a konstruktort, de a többi objektum nem.</p></li><li><p>Menjünk át az kódon, és a <code>singleton</code> konstruktorának minden közvetlen hívását cseréljük le a statikus létrehozási metódus hívására.</p></li></ol><p>Az adatbázis kapcsolat kezelése egy gyakori példa a <code>Singleton</code> tervezési minta használatára. Íme egy példa egy <code>Singleton</code> osztályra az adatbázis kapcsolat létrehozásához Java-ban:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">import</span> <span class="token import"><span class="token namespace">java<span class="token punctuation">.</span>sql<span class="token punctuation">.</span></span><span class="token class-name">Connection</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">java<span class="token punctuation">.</span>sql<span class="token punctuation">.</span></span><span class="token class-name">DriverManager</span></span><span class="token punctuation">;</span>
<span class="token keyword">import</span> <span class="token import"><span class="token namespace">java<span class="token punctuation">.</span>sql<span class="token punctuation">.</span></span><span class="token class-name">SQLException</span></span><span class="token punctuation">;</span>

<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">DatabaseConnection</span> <span class="token punctuation">{</span>
    <span class="token keyword">private</span> <span class="token keyword">static</span> <span class="token class-name">DatabaseConnection</span> instance<span class="token punctuation">;</span>
    <span class="token keyword">private</span> <span class="token class-name">Connection</span> connection<span class="token punctuation">;</span>

    <span class="token keyword">private</span> <span class="token class-name">DatabaseConnection</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">try</span> <span class="token punctuation">{</span>
            <span class="token comment">// Adatbázis kapcsolat inicializálása</span>
            <span class="token class-name">String</span> url <span class="token operator">=</span> <span class="token string">&quot;jdbc:mysql://localhost:3306/mydatabase&quot;</span><span class="token punctuation">;</span>
            <span class="token class-name">String</span> username <span class="token operator">=</span> <span class="token string">&quot;username&quot;</span><span class="token punctuation">;</span>
            <span class="token class-name">String</span> password <span class="token operator">=</span> <span class="token string">&quot;password&quot;</span><span class="token punctuation">;</span>
            connection <span class="token operator">=</span> <span class="token class-name">DriverManager</span><span class="token punctuation">.</span><span class="token function">getConnection</span><span class="token punctuation">(</span>url<span class="token punctuation">,</span> username<span class="token punctuation">,</span> password<span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">SQLException</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span>
            e<span class="token punctuation">.</span><span class="token function">printStackTrace</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token class-name">DatabaseConnection</span> <span class="token function">getInstance</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">if</span> <span class="token punctuation">(</span>instance <span class="token operator">==</span> <span class="token keyword">null</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
            instance <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">DatabaseConnection</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
        <span class="token punctuation">}</span>
        <span class="token keyword">return</span> instance<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token class-name">Connection</span> <span class="token function">getConnection</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">return</span> connection<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ebben a példában a <code>DatabaseConnection</code> osztály felelős az adatbázis kapcsolat létrehozásáért és az egyetlen példányt tartalmazza. A <code>Singleton</code> osztály, így garantált, hogy csak egyetlen adatbázis kapcsolat példány jön létre az alkalmazásban.</p><p>Az adatbázis kapcsolat eléréséhez az alkalmazásban a következőképpen lehet használni ezt a <code>Singleton</code> osztályt:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token class-name">DatabaseConnection</span> dbConnection <span class="token operator">=</span> <span class="token class-name">DatabaseConnection</span><span class="token punctuation">.</span><span class="token function">getInstance</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token keyword">try</span> <span class="token punctuation">{</span>
    <span class="token class-name">Connection</span> connection <span class="token operator">=</span> dbConnection<span class="token punctuation">.</span><span class="token function">getConnection</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

    <span class="token comment">// Itt már használhatod az adatbázis kapcsolatot a lekérdezések végrehajtására</span>
<span class="token punctuation">}</span> <span class="token keyword">catch</span> <span class="token punctuation">(</span><span class="token class-name">SQLException</span> e<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    e<span class="token punctuation">.</span><span class="token function">printStackTrace</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ezzel elkerülhető, hogy több kapcsolat példány jöjjön létre, és biztosítva van, hogy az alkalmazás egésze ugyanazt a kapcsolatot használja.</p><h3 id="elonyok-es-hatranyok-1" tabindex="-1"><a class="header-anchor" href="#elonyok-es-hatranyok-1" aria-hidden="true">#</a> Előnyök és hátrányok</h3><p><i class="fa-solid fa-plus" style="color:green;"></i> Biztos lehetsz benne, hogy egy osztálynak csak egyetlen példánya van.</p><p><i class="fa-solid fa-plus" style="color:green;"></i> Globális hozzáférési pontot kapunk ehhez a példányhoz.</p><p><i class="fa-solid fa-plus" style="color:green;"></i> A singleton objektum csak akkor inicializálódik, amikor először kérik.</p><p><i class="fa-solid fa-minus" style="color:red;"></i> Megsérti az egyetlen felelősség elvét. A minta egyszerre két problémát old meg.</p><p><i class="fa-solid fa-minus" style="color:red;"></i> A minta speciális kezelést igényel többszálas környezetben, hogy több szál ne hozzon létre többször egy singleton objektumot.</p><h2 id="builder" tabindex="-1"><a class="header-anchor" href="#builder" aria-hidden="true">#</a> Builder</h2><figure><img src="`+m+'" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="celkituzes-2" tabindex="-1"><a class="header-anchor" href="#celkituzes-2" aria-hidden="true">#</a> Célkitűzés</h3><p>A <code>Builder</code> egy olyan tervezési minta, amely lehetővé teszi, hogy lépésről lépésre összetett objektumokat építsünk fel. A minta lehetővé teszi, hogy egy objektum különböző típusait és reprezentációit ugyanazzal a kóddal hozzuk létre.</p><h3 id="problema-2" tabindex="-1"><a class="header-anchor" href="#problema-2" aria-hidden="true">#</a> Probléma</h3><p>Képzeljünk el egy összetett objektumot, amely számos mező és egymásba ágyazott objektum fáradtságos, lépésről lépésre történő inicializálását igényli. Az ilyen inicializálási kód általában egy konstruktorban van elrejtve, rengeteg paraméterrel. Vagy ami még rosszabb: szétszórva a kódban.</p><figure><img src="'+z+'" alt="Azzal, hogy minden lehetséges objektumkonfigurációhoz egy-egy alosztályt hozol létre, túlságosan bonyolulttá teheted a programot." tabindex="0" loading="lazy"><figcaption>Azzal, hogy minden lehetséges objektumkonfigurációhoz egy-egy alosztályt hozol létre, túlságosan bonyolulttá teheted a programot.</figcaption></figure><p>Gondoljunk például egy <code>House</code> objektum létrehozására. Egy egyszerű ház megépítéséhez négy falat és egy padlót kell építenünk, be kell szerelnünk egy ajtót, be kell szerelnünk egy pár ablakot, és még fel kell építenünk a tetőt. De mi van akkor, ha egy nagyobb, látványosabb házat szeretnél, hátsó udvarral és egyéb extrákkal (<em>például fűtési rendszerrel, vízvezetékkel és elektromos vezetékekkel</em>)?</p><p>A legegyszerűbb megoldás az alap <code>House</code> osztály kiterjesztése és egy sor alosztály létrehozása a paraméterek összes kombinációjának lefedésére. De végül jelentős számú alosztály lesz a végeredmény. Minden új paraméter, például a terasz kialakítása, még tovább növeli ezt a hierarchiát.</p><p>Van egy másik megközelítés, amely nem jár alosztályok létrehozásával. Létrehozhatsz egy hatalmas konstruktort közvetlenül az alap <code>House</code> osztályban az összes lehetséges paraméterrel, amely a ház objektumot vezérli. Bár ez a megközelítés valóban kiküszöböli az alosztályok szükségességét, egy másik problémát is okoz.</p><figure><img src="'+g+'" alt="A sok paraméterrel rendelkező konstruktornak megvan a maga hátránya: nem minden paraméterre van mindig szükség." tabindex="0" loading="lazy"><figcaption>A sok paraméterrel rendelkező konstruktornak megvan a maga hátránya: nem minden paraméterre van mindig szükség.</figcaption></figure><p>A legtöbb esetben a paraméterek többsége nem lesz felhasználva, ami a <strong>konstruktorhívásokat elég csúnyává teszi</strong>. Például a házaknak csak egy töredéke rendelkezik medencével, így a medencékkel kapcsolatos paraméterek tízből kilencszer használhatatlanok lesznek.</p><h3 id="megoldas-2" tabindex="-1"><a class="header-anchor" href="#megoldas-2" aria-hidden="true">#</a> Megoldás</h3><p>A <code>Builder</code> minta azt csinálja, hogy az objektum kódját vonja ki a saját osztályából, és helyezi át különálló objektumokba, úgynevezett &quot;<strong>builder</strong>&quot;-ekbe.</p><figure><img src="'+v+'" alt="A Builder mintával lépésről lépésre építhetünk fel összetett objektumokat. A Builder nem engedi, hogy más objektumok hozzáférjenek, amíg az épül." tabindex="0" loading="lazy"><figcaption>A Builder mintával lépésről lépésre építhetünk fel összetett objektumokat. A Builder nem engedi, hogy más objektumok hozzáférjenek, amíg az épül.</figcaption></figure><p>A minta az objektumok építését lépések sorozatába szervezi (<code>buildWalls</code>, <code>buildDoor</code>, stb.). Egy objektum létrehozásához ezeknek a lépéseknek a sorozatát hajtja végre egy <code>Builder</code> objektumon. A fontos rész az, hogy nem kell az összes lépést meghívni. Csak azokat a lépéseket hívhatjuk meg, amelyek az objektum adott konfigurációjának létrehozásához szükségesek.</p><p>Néhány építési lépés eltérő végrehajtást igényelhet, ha a termék különböző reprezentációit kell megépítenie. Például egy faház falait lehet fából építeni, de a várfalakat kőből kell építeni.</p><p>Ebben az esetben több különböző <code>Builder</code> osztályt hozhatsz létre, amelyek ugyanazokat az építési lépéseket valósítják meg, de különböző módon. Ezután ezeket használhatjuk az építési folyamatban (<em>azaz az építési lépések hívásainak rendezett halmazában)</em> különböző típusú objektumok előállítására.</p><figure><img src="'+y+'" alt="A különböző builderek ugyanazt a feladatot különböző módon hajtják végre." tabindex="0" loading="lazy"><figcaption>A különböző builderek ugyanazt a feladatot különböző módon hajtják végre.</figcaption></figure><p>Képzeljünk el például egy építészt, aki mindent fából és üvegből épít, egy másikat, aki mindent kőből és vasból épít, egy harmadikat pedig, aki aranyat és gyémántot használ. Ha ugyanazt a lépéssort hívjuk meg, akkor az első építésztől kapunk egy átlagos házat, a másodiktól egy kis kastélyt, a harmadikatól pedig egy palotát. Ez azonban csak akkor működne, ha az építési lépéseket hívó kód képes lenne egy közös interfész segítségével interakcióba lépni az építőkkel.</p><h3 id="director" tabindex="-1"><a class="header-anchor" href="#director" aria-hidden="true">#</a> Director</h3><p>Tovább is mehetünk, és a termék létrehozásához használt építő lépések hívássorozatát egy külön osztályba, a directorba helyezhetjük. A <code>director</code> osztály határozza meg az építési lépések végrehajtásának sorrendjét, míg a builder biztosítja a lépések végrehajtását.</p><figure><img src="'+b+`" alt="A Director tudja, hogy milyen építési lépéseket kell végrehajtania ahhoz, hogy működőképes terméket kapjunk." tabindex="0" loading="lazy"><figcaption>A Director tudja, hogy milyen építési lépéseket kell végrehajtania ahhoz, hogy működőképes terméket kapjunk.</figcaption></figure><p>Nem feltétlenül szükséges, hogy a programban legyen egy <code>Director</code> osztály. Az építési lépéseket mindig meghívhatja egy adott sorrendben közvetlenül a klienskódból. A <code>Director</code> osztály használata jó lehet a különböző építési rutinok elhelyezésére, hogy újra felhasználhassuk őket a programjainkban.</p><p>Ráadásul a <code>director</code> osztály teljesen elrejti a terméképítés részleteit a klienskód elől.</p><h3 id="hogyan-kell-megvalositani-2" tabindex="-1"><a class="header-anchor" href="#hogyan-kell-megvalositani-2" aria-hidden="true">#</a> Hogyan kell megvalósítani?</h3><p>A Builder tervezési minta segít létrehozni és konfigurálni objektumokat lépésről lépésre, különválasztva az objektum összeállítását az objektum tulajdonságainak beállításától. Itt van egy egyszerű példa egy <code>PizzaBuilder</code> osztályra, amely segít egy pizzát készíteni:</p><div class="language-java line-numbers-mode" data-ext="java"><pre class="language-java"><code><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">Pizza</span> <span class="token punctuation">{</span>
    <span class="token keyword">private</span> <span class="token class-name">String</span> dough<span class="token punctuation">;</span>
    <span class="token keyword">private</span> <span class="token class-name">String</span> sauce<span class="token punctuation">;</span>
    <span class="token keyword">private</span> <span class="token class-name">String</span> topping<span class="token punctuation">;</span>

    <span class="token keyword">public</span> <span class="token class-name">Pizza</span><span class="token punctuation">(</span><span class="token class-name">String</span> dough<span class="token punctuation">,</span> <span class="token class-name">String</span> sauce<span class="token punctuation">,</span> <span class="token class-name">String</span> topping<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>dough <span class="token operator">=</span> dough<span class="token punctuation">;</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>sauce <span class="token operator">=</span> sauce<span class="token punctuation">;</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>topping <span class="token operator">=</span> topping<span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token comment">// Getterek a tulajdonságokhoz [...]</span>

    <span class="token annotation punctuation">@Override</span>
    <span class="token keyword">public</span> <span class="token class-name">String</span> <span class="token function">toString</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">return</span> <span class="token string">&quot;Pizza with &quot;</span> <span class="token operator">+</span> dough <span class="token operator">+</span> <span class="token string">&quot; dough, &quot;</span> 
                <span class="token operator">+</span> sauce <span class="token operator">+</span> <span class="token string">&quot; sauce, and &quot;</span> <span class="token operator">+</span> topping <span class="token operator">+</span> <span class="token string">&quot; topping.&quot;</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>

<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">PizzaBuilder</span> <span class="token punctuation">{</span>
    <span class="token keyword">private</span> <span class="token class-name">String</span> dough<span class="token punctuation">;</span>
    <span class="token keyword">private</span> <span class="token class-name">String</span> sauce<span class="token punctuation">;</span>
    <span class="token keyword">private</span> <span class="token class-name">String</span> topping<span class="token punctuation">;</span>

    <span class="token keyword">public</span> <span class="token class-name">PizzaBuilder</span> <span class="token function">setDough</span><span class="token punctuation">(</span><span class="token class-name">String</span> dough<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>dough <span class="token operator">=</span> dough<span class="token punctuation">;</span>
        <span class="token keyword">return</span> <span class="token keyword">this</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token class-name">PizzaBuilder</span> <span class="token function">setSauce</span><span class="token punctuation">(</span><span class="token class-name">String</span> sauce<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>sauce <span class="token operator">=</span> sauce<span class="token punctuation">;</span>
        <span class="token keyword">return</span> <span class="token keyword">this</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token class-name">PizzaBuilder</span> <span class="token function">setTopping</span><span class="token punctuation">(</span><span class="token class-name">String</span> topping<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">this</span><span class="token punctuation">.</span>topping <span class="token operator">=</span> topping<span class="token punctuation">;</span>
        <span class="token keyword">return</span> <span class="token keyword">this</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>

    <span class="token keyword">public</span> <span class="token class-name">Pizza</span> <span class="token function">build</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token class-name">Pizza</span><span class="token punctuation">(</span>dough<span class="token punctuation">,</span> sauce<span class="token punctuation">,</span> topping<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>

<span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">PizzaExample</span> <span class="token punctuation">{</span>
    <span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token keyword">void</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token class-name">String</span><span class="token punctuation">[</span><span class="token punctuation">]</span> args<span class="token punctuation">)</span> <span class="token punctuation">{</span>
        <span class="token class-name">Pizza</span> pizza <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">PizzaBuilder</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">setDough</span><span class="token punctuation">(</span><span class="token string">&quot;Thin&quot;</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">setSauce</span><span class="token punctuation">(</span><span class="token string">&quot;Tomato&quot;</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">setTopping</span><span class="token punctuation">(</span><span class="token string">&quot;Cheese&quot;</span><span class="token punctuation">)</span>
            <span class="token punctuation">.</span><span class="token function">build</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span>pizza<span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Ebben a példában a <code>Pizza</code> osztályt egy <code>PizzaBuilder</code> osztály segítségével hozzuk létre. A <code>PizzaBuilder</code> lehetővé teszi a pizzatészta, szósz és feltét beállítását, majd a <code>build</code> metódussal elkészíti és visszaadja a kívánt pizzát. Ez a tervezési minta segít elkerülni az összetett konstruktorokat, és könnyen konfigurálható objektumok létrehozását teszi lehetővé.</p><h3 id="elonyok-es-hatranyok-2" tabindex="-1"><a class="header-anchor" href="#elonyok-es-hatranyok-2" aria-hidden="true">#</a> Előnyök és hátrányok</h3><p><i class="fa-solid fa-plus" style="color:green;"></i> Objektumok létrehozása fokozatosan, lépésről lépésre történhet.<br><i class="fa-solid fa-plus" style="color:green;"></i> Ugyanazt a kódot újra használhatja fel különféle termékábrázolások elkészítésekor.<br><i class="fa-solid fa-plus" style="color:green;"></i> Az Egyetlen Felelősség Elve segít elkülöníteni a komplex kódot a termék üzleti logikájától.</p><p><i class="fa-solid fa-minus" style="color:red;"></i> A kód általános összetettsége növekszik, mivel a minta több új osztály létrehozását igényli.</p><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="footnote1" class="footnote-item"><p><em>Gang of Four</em> <a href="#footnote-ref1" class="footnote-backref">↩︎</a></p></li><li id="footnote2" class="footnote-item"><p><em>Olyan nyelvi kifejezés, amely állandó, rögzített elemekkel fordul elő minden szövegben és szövegkörnyezetben.</em> <a href="#footnote-ref2" class="footnote-backref">↩︎</a></p></li><li id="footnote3" class="footnote-item"><p><em>A mitotikus alak olyan sejt, amely osztódási folyamatban van, és két új sejt jön létre. Ezt a folyamatot mitózisnak nevezik.</em> <a href="#footnote-ref3" class="footnote-backref">↩︎</a></p></li><li id="footnote4" class="footnote-item"><p><em>Azt jelenti, hogy egy erőforrást vagy objektumot csak akkor hozunk létre, amikor valóban szükség van rá, azaz <em>&quot;lustán&quot;</em>, későbbi időpontban inicializáljuk. A lényege, hogy az erőforrás vagy az objektum inicializálását elhalasztjuk addig, amíg valamilyen művelet, hívás vagy kérés történik, amely valójában használja az adott erőforrást.</em> <a href="#footnote-ref4" class="footnote-backref">↩︎</a></p></li></ol></section>`,61);function x(E,S){const e=o("ExternalLinkIcon");return l(),i("div",null,[f,n("p",null,[a("A "),j,a(" minta egyszerre két problémát old meg, ami sérti az "),n("a",A,[a("Egyetlen felelősség elvét"),p(e)]),a(":")]),w])}const P=t(h,[["render",x],["__file","lesson1p.html.vue"]]);export{P as default};
